ow"><i class="fas fa-times"></i></button></div></div><input name="item_notes[]" class="form-control form-control-sm mt-2" value="{{ old('item_notes.'.$i,$editing ? $target->items[$i]->notes ?? '':'') }}" placeholder="Category-specific note (optional)"></div>@endforeach</div></div><div class="mt-3"><a href="{{ route('admin.sales-targets.index') }}" class="btn btn-light">Cancel</a><button class="btn btn-primary float-right"><i class="fas fa-save mr-1"></i> Save Sales Target</button></div></form>
