@push('scripts')<script>function wireRows(){document.querySelectorAll('.remove-row').forEach(b=>b.onclick=()=>{if(document.querySelectorAll('.target-row').length>1)b.closest('.target-row').remove();});$('.category-select').select2({width:'100%'});}$('#addRow').on('click',()=>{document.querySelector('#targetRows').insertAdjacentHTML('beforeend',document.querySelector('#rowTemplate').innerHTML);wireRows();});wireRows();$('#period_type').on('change',function(){let s=new Date($('#starts_on').val()+'T00:00:00'),d={daily:0,weekly:6,monthly:new Date(s.getFullYear(),s.getMonth()+1,0).getDate()-1,quarterly_3:89,quarterly_6:179,yearly:364}[this.value];if(!isNaN(s)&&d!==undefined){s.setDate(s.getDate()+d);$('#ends_on').val(s.toISOString().slice(0,10));}});</script>@endpush
